package edu.rice.comp322.solutions;

import edu.rice.comp322.provided.trees.GList;
import edu.rice.comp322.provided.trees.Tree;

public class TreeSolutions {

    // @TODO Implement tree sum
    public static Integer problemOne(Tree<Integer> tree) {
        if (tree.isEmpty()) {
            return 0;
        }
        return tree.value() + tree.children().fold(0, (sum, child) -> sum + problemOne(child));
    }

    // @TODO Implement tree sum using higher order list functions
    public static Integer problemTwo(Tree<Integer> tree) {
        if (tree.isEmpty()) {
            return 0;
        }
        return tree.children()
            .filter(child -> !child.isEmpty())
            .map(TreeSolutions::problemTwo)
            .fold(tree.value(), Integer::sum);
    }

    /*
     * Problem 3's solution should be written in the Tree.java class at line 118.
     */

    // @TODO Calculate the sum of the elements of the tree using tree fold
    public static Integer problemFour(Tree<Integer> tree) {
        return tree.fold(0, Integer::sum);
    }

}

package edu.rice.comp322.solutions;

import edu.rice.comp322.provided.streams.models.Customer;
import edu.rice.comp322.provided.streams.models.Order;
import edu.rice.comp322.provided.streams.models.Product;
import edu.rice.comp322.provided.streams.provided.DiscountObject;
import edu.rice.comp322.provided.streams.repos.CustomerRepo;
import edu.rice.comp322.provided.streams.repos.OrderRepo;
import edu.rice.comp322.provided.streams.repos.ProductRepo;

import java.util.*;

import java.time.LocalDate;
import java.util.stream.Collectors;

/**
 * A class containing all of the students implemented solutions to the stream problems.
 */
public class StreamSolutions {
    private static final LocalDate FEBRUARY_START = LocalDate.of(2021, 2, 1);
    private static final LocalDate MARCH_START = LocalDate.of(2021, 3, 1);


    /**
     * Use this function with the appropriate streams solution test to ensure repos load correctly.
     */
    public static List<Long> problemZeroSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        List<Long> counts = new ArrayList<>();
        counts.add(customerRepo.findAll().stream().count());
        counts.add(orderRepo.findAll().stream().count());
        counts.add(productRepo.findAll().stream().count());

        return counts;
    }

    /**
     * Use this function with the appropriate streams solution test to ensure repos load correctly.
     */
    public static List<Long> problemZeroPar(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        List<Long> counts = new ArrayList<>();
        counts.add(customerRepo.findAll().parallelStream().count());
        counts.add(orderRepo.findAll().parallelStream().count());
        counts.add(productRepo.findAll().parallelStream().count());

        return counts;
    }

    // TODO: Implement problem one using sequential streams
    public static Double problemOneSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return orderRevenue(orderRepo.findAll().stream()
            .filter(order -> isInMonth(order, FEBRUARY_START)), false);
    }

    // TODO: Implement problem one using parallel streams
    public static Double problemOnePar(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return orderRevenue(orderRepo.findAll().parallelStream()
            .filter(order -> isInMonth(order, FEBRUARY_START)), false);
    }

    // TODO: Implement problem two using sequential streams
    public static Set<Long> problemTwoSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return orderRepo.findAll().stream()
            .sorted(Comparator.comparing(Order::getOrderDate).reversed().thenComparing(Order::getId, Comparator.reverseOrder()))
            .limit(5)
            .map(Order::getId)
            .collect(Collectors.toSet());
    }

    // TODO: Implement problem two using parallel streams
    public static Set<Long> problemTwoPar(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return orderRepo.findAll().parallelStream()
            .sorted(Comparator.comparing(Order::getOrderDate).reversed().thenComparing(Order::getId, Comparator.reverseOrder()))
            .limit(5)
            .map(Order::getId)
            .collect(Collectors.toSet());
    }

    // TODO: Implement problem three using sequential streams
    public static Long problemThreeSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return orderRepo.findAll().stream()
            .map(order -> order.getCustomer().getId())
            .distinct()
            .count();
    }

    // TODO: Implement problem three using parallel streams
    public static Long problemThreePar(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return orderRepo.findAll().parallelStream()
            .map(order -> order.getCustomer().getId())
            .distinct()
            .count();
    }

    // TODO: Implement problem four using sequential streams
    public static Double problemFourSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return orderDiscount(orderRepo.findAll().stream()
            .filter(order -> isInMonth(order, MARCH_START)));
    }

    // TODO: Implement problem four using parallel streams
    public static Double problemFourPar(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return orderDiscount(orderRepo.findAll().parallelStream()
            .filter(order -> isInMonth(order, MARCH_START)));
    }

    // TODO: Implement problem five using sequential streams
    public static Map<Long, Double> problemFiveSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return customerSpendMap(orderRepo.findAll().stream(), false);
    }

    // TODO: Implement problem five using parallel streams
    public static Map<Long, Double> problemFivePar(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return customerSpendMap(orderRepo.findAll().parallelStream(), false);
    }

    // TODO: Implement problem six using sequential streams
    public static Map<String, Double> problemSixSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return productRepo.findAll().stream()
            .collect(Collectors.groupingBy(
                Product::getCategory,
                Collectors.averagingDouble(Product::getFullPrice)));
    }

    // TODO: Implement problem six using parallel streams
    public static Map<String, Double> problemSixPar(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return productRepo.findAll().parallelStream()
            .collect(Collectors.groupingByConcurrent(
                Product::getCategory,
                Collectors.averagingDouble(Product::getFullPrice)));
    }

    // TODO: Implement problem seven using sequential streams
    public static Map<Long, Set<Long>> problemSevenSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return techOrdersMap(orderRepo.findAll().stream());
    }

    // TODO: Implement problem seven using parallel streams
    public static Map<Long, Set<Long>> problemSevenPar(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return techOrdersMap(orderRepo.findAll().parallelStream());
    }

    // TODO: Implement problem eight using sequential streams
    public static Map<Long, Double> problemEightSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return tierZeroUtilization(customerRepo.findAll().stream(), orderRepo.findAll().stream());
    }

    // TODO: Implement problem eight using parallel streams
    public static Map<Long, Double> problemEightPar(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return tierZeroUtilization(customerRepo.findAll().parallelStream(), orderRepo.findAll().parallelStream());
    }

    private static boolean isInMonth(Order order, LocalDate monthStart) {
        LocalDate monthEnd = monthStart.plusMonths(1);
        return !order.getOrderDate().isBefore(monthStart) && order.getOrderDate().isBefore(monthEnd);
    }

    private static Double orderRevenue(java.util.stream.Stream<Order> orderStream, boolean useDiscountedPrice) {
        return orderStream
            .flatMap(order -> order.getProducts().stream().map(product -> new DiscountObject(order.getCustomer(), product)))
            .mapToDouble(item -> useDiscountedPrice ? item.getPurchasedPrice() : item.getFullPrice())
            .sum();
    }

    private static Double orderDiscount(java.util.stream.Stream<Order> orderStream) {
        return orderStream
            .flatMap(order -> order.getProducts().stream().map(product -> new DiscountObject(order.getCustomer(), product)))
            .mapToDouble(DiscountObject::getDiscount)
            .sum();
    }

    private static Map<Long, Double> customerSpendMap(java.util.stream.Stream<Order> orderStream, boolean useDiscountedPrice) {
        return orderStream
            .flatMap(order -> order.getProducts().stream()
                .map(product -> Map.entry(order.getCustomer().getId(), new DiscountObject(order.getCustomer(), product))))
            .collect(Collectors.groupingBy(
                Map.Entry::getKey,
                Collectors.summingDouble(entry -> useDiscountedPrice
                    ? entry.getValue().getPurchasedPrice()
                    : entry.getValue().getFullPrice())));
    }

    private static Map<Long, Set<Long>> techOrdersMap(java.util.stream.Stream<Order> orderStream) {
        return orderStream
            .flatMap(order -> order.getProducts().stream()
                .filter(product -> "Tech".equals(product.getCategory()))
                .map(product -> Map.entry(product.getId(), order.getCustomer().getId())))
            .collect(Collectors.groupingBy(
                Map.Entry::getKey,
                Collectors.mapping(Map.Entry::getValue, Collectors.toSet())));
    }

    private static Map<Long, Double> tierZeroUtilization(java.util.stream.Stream<Customer> customerStream,
                                                         java.util.stream.Stream<Order> orderStream) {
        List<Order> orders = orderStream.collect(Collectors.toList());
        Map<Long, Double> spentAtDiscountedPrice = customerSpendMap(orders.stream(), true);
        Map<Long, Double> spentAtFullPrice = customerSpendMap(orders.stream(), false);
        return customerStream
            .filter(customer -> customer.getTier() == 0)
            .collect(Collectors.toMap(
                Customer::getId,
                customer -> {
                    double fullPriceTotal = spentAtFullPrice.getOrDefault(customer.getId(), 0.0);
                    return fullPriceTotal == 0.0
                        ? 0.0
                        : spentAtDiscountedPrice.getOrDefault(customer.getId(), 0.0) / fullPriceTotal;
                }));
    }
}

package edu.rice.comp322.provided.trees;

import java.util.function.BiFunction;
import java.util.function.Function;
import java.util.NoSuchElementException;
import java.util.function.Predicate;

/**
 * A very simple functional tree implementation
 * A tree can either be Empty, or a Node.
 */
public interface Tree<T> {

    /**
     * Create a new empty tree of the given parameter type.
     */
    @SuppressWarnings("unchecked")
    static <T> Tree<T> empty() {
        return (Tree<T>) Tree.Empty.SINGLETON;
    }

    /**
     * Builder for making a tree node.
     */
    static <T> Tree<T> makeNode(T value, GList<Tree<T>> children) {
        return new Node<>(value, children);
    }

    /**
     * Getter for value.
     */
    T value();

    /**
     * Getter for the children.
     */
    GList<Tree<T>> children();

    /**
     * Return true if this is an empty tree.
     */
    boolean isEmpty();

    /** Returns a new tree equal to the old tree with the function applied to each value. */
    <R> Tree<R> map(Function<T, R> f);

    /** Returns a new tree equal to all the nodes in the old tree satisfying the predicate. */
    Tree<T> filter(Predicate<T> p);

    <U> U fold(U zero,  BiFunction<U, T, U> operator);


    /**
     * Class Node implements a non-empty tree.
     * A Node has a value, and a GList of children (which could be empty).
     */
    class Node<T> implements Tree<T> {
        private final T value;
        private final GList<Tree<T>> children;

        public Node(T value, GList<Tree<T>> children) {
            this.value = value;
            this.children = children;
        }

        @Override
        public T value() {
            return value;
        }

        @Override
        public GList<Tree<T>> children() {
            return children;
        }

        @Override
        public boolean isEmpty() {
            return false;
        }

        /**
         * It should return a new tree equal to the old tree with the function applied to each value.
         * @param f   the function for mapping every value in the tree
         * @param <R> the type of the values in the new tree
         * @return the tree with the exact same structure as the original one, but with f applied to each value
         */
        @Override
        public <R> Tree<R> map(Function<T, R> f) {
            return Tree.makeNode(f.apply(value()), children().map(tree -> tree.map(f)));
        }

        /**
         * It should return a new tree that only contains the nodes whose values satisfy the predicate.
         * @param p   the predicate for determining if the node should stay in the tree
         */
        @Override
        public Tree<T> filter(Predicate<T> p) {
            var newChildren = children().map(child -> child.filter(p)).filter(child -> !child.isEmpty());
            if (p.test(value())) {
                return makeNode(value(), newChildren);
            } else if (newChildren.isEmpty()) {
                return empty();
            } else {
                return makeTreeHelper(newChildren);
            }
        }

        /**
         * @TODO Implement this function to complete problem 3 of section one of hw 1
         *
         * @param zero The base value to start the fold operation with. Should be of type U.
         * @param operator The function for how to combine a new tree's value into the accumulated
         *                 value.
         * @param <U> The return type as well as the type of the zero value.
         * @return a value of type U representing the folding of the entire tree.
         */
        @Override
        public <U> U fold(U zero, BiFunction<U, T, U> operator) {
            U accumulated = operator.apply(zero, value());
            return children().fold(accumulated, (acc, child) -> child.fold(acc, operator));
        }

        /**
         * A helper function for making a tree out of a GList of trees. It picks the root of the first
         * tree as the root of the result, then adds the remaining trees to the children of the first tree
         */
        private Tree<T> makeTreeHelper(GList<Tree<T>> treeList) {
            if (treeList.isEmpty()) {
                return empty();
            } else {
                var firstChild = treeList.head();
                return makeNode(firstChild.value(), firstChild.children().appendAll(treeList.tail()));
            }
        }

    }

    /**
     * The empty tree.
     */
    class Empty<T> implements Tree<T> {
        /**
         * The constructor is private.
         */
        private Empty() {}

        /**
         * There is only one empty tree.
         */
        private static final Tree<?> SINGLETON = new Empty<>();

        /**
         * The map for an empty tree is simple: just return an empty tree.
         */
        @Override
        public <R> Tree<R> map(Function<T, R> f) {
            return empty();
        }

        /**
         * The filter for an empty tree is simple: just return an empty tree.
         */
        @Override
        public Tree<T> filter(Predicate<T> p) {
            return empty();
        }

        @Override
        public <U> U fold(U zero, BiFunction<U, T, U> operator) {
            return zero;
        }

        @Override
        public T value() {
            throw new NoSuchElementException("can't get a value from an empty tree");
        }

        @Override
        public GList<Tree<T>> children() {
            throw new NoSuchElementException("can't get children from an empty tree");
        }

        @Override
        public boolean isEmpty() {
            return true;
        }

    }
}

