import static edu.rice.comp322.solutions.StreamSolutions.problemSixPar;
import static edu.rice.comp322.solutions.StreamSolutions.problemSixSeq;

@SpringBootTest(classes = DemoApplication.class)
public class StreamSolutionsAgentTest {

    @Autowired
    private CustomerRepo customerRepo;

    @Autowired
    private OrderRepo orderRepo;

    @Autowired
    private ProductRepo productRepo;

    @Transactional
    @Test
    public void problemSixMatchesImperativeAverage() {
        Map<String, double[]> totals = new HashMap<>();
        for (Product product : productRepo.findAll()) {
            totals.computeIfAbsent(product.getCategory(), ignored -> new double[2]);
            totals.get(product.getCategory())[0] += product.getFullPrice();
            totals.get(product.getCategory())[1] += 1.0;
        }

        Map<String, Double> expected = new HashMap<>();
        for (Map.Entry<String, double[]> entry : totals.entrySet()) {
            expected.put(entry.getKey(), entry.getValue()[0] / entry.getValue()[1]);
        }

        assertDoubleMapEquals(expected, problemSixSeq(customerRepo, orderRepo, productRepo));
        assertDoubleMapEquals(expected, problemSixPar(customerRepo, orderRepo, productRepo));
    }

    @Transactional
    @Test
    public void problemSevenMatchesImperativeTechCustomerMap() {
        Map<Long, Set<Long>> expected = new HashMap<>();
        for (Order order : orderRepo.findAll()) {
            for (Product product : order.getProducts()) {
                if ("Tech".equals(product.getCategory())) {
                    expected.computeIfAbsent(product.getId(), ignored -> new HashSet<>())
                        .add(order.getCustomer().getId());
                }
            }
        }

        Assertions.assertEquals(expected, problemSevenSeq(customerRepo, orderRepo, productRepo));
        Assertions.assertEquals(expected, problemSevenPar(customerRepo, orderRepo, productRepo));
    }

    @Transactional
    @Test
    public void problemEightMatchesImperativeTierZeroUtilization() {
        Map<Long, Double> actualSpent = new HashMap<>();
        Map<Long, Double> fullPriceSpent = new HashMap<>();

        for (Order order : orderRepo.findAll()) {
            long customerId = order.getCustomer().getId();
            for (Product product : order.getProducts()) {
                DiscountObject discount = new DiscountObject(order.getCustomer(), product);
                actualSpent.merge(customerId, discount.getPurchasedPrice(), Double::sum);
                fullPriceSpent.merge(customerId, discount.getFullPrice(), Double::sum);
            }
        }

        Map<Long, Double> expected = new HashMap<>();
        for (Customer customer : customerRepo.findAll()) {
            if (customer.getTier() == 0) {
                double full = fullPriceSpent.getOrDefault(customer.getId(), 0.0);
                double actual = actualSpent.getOrDefault(customer.getId(), 0.0);
                expected.put(customer.getId(), full == 0.0 ? 0.0 : actual / full);
            }
        }

        assertDoubleMapEquals(expected, problemEightSeq(customerRepo, orderRepo, productRepo));
        assertDoubleMapEquals(expected, problemEightPar(customerRepo, orderRepo, productRepo));
    }

    private static <K> void assertDoubleMapEquals(Map<K, Double> expected, Map<K, Double> actual) {
        Assertions.assertEquals(expected.keySet(), actual.keySet());
        for (K key : expected.keySet()) {
            Assertions.assertEquals(expected.get(key), actual.get(key), 1.0e-9);
        }
    }
}

